const filteredConfigValues = page.variables.filteredConfigValues;
const fetchValues = queries.fetchConfigValues.data || [];
const fetchDetails = queries.fetchConfigDetails.data || {};
const dimensionStrings = page.variables.configValueDimensionString?.value || [];
const marketplaceStrings = page.variables.configValueMarketplaceString?.value || [];

return filteredConfigValues.map((item, i) => {
  const safeItem = item || {};
  const valueType = safeItem.value.type || "";

  const currentValue =
    item === null
      ? "null"
      : valueType === "float_value_v2"
        ? safeItem.value.string_value
        : valueType === "float_array_value_v2"
          ? `[${safeItem.value.string_value?.[`${valueType.split("_array_value")[0]}_values_v2`] || ""}]`
          : valueType.includes("array")
            ? safeItem.value.string_value?.[`${valueType.split("_array_value")[0]}_values`] || ""
            : safeItem.value.string_value;

  const rolloutData = fetchValues[i];

  let rolloutDetails = "N.A.";

  if (rolloutData?.is_in_rollout_phase) {
    const inputType = fetchDetails["Value Type"]?.slice(5)?.toLowerCase();

    let formattedValue;
    switch (inputType) {
      case "string":
        formattedValue = currentValue;
        break;
      case "int":
      case "float":
        formattedValue = parseFloat(currentValue);
        break;
      case "boolean":
        formattedValue = currentValue;
        break;
      case "string_array":
      case "int_array":
      case "boolean_array":
        formattedValue = JSON.stringify(currentValue);
        break;
      case "float_array":
        formattedValue = currentValue?.toString();
        break;
      case "json":
        formattedValue = currentValue;
        break;
      default:
        formattedValue = currentValue;
    }

    const unitType =
      fetchValues[0]?.deployment_strategy?.custom_deployment_strategy?.deployment_unit_type
        ?.slice(21) || "";

    const unitValues =
      fetchValues[0]?.deployment_strategy?.custom_deployment_strategy?.deployment_unit_values || [];

    rolloutDetails = `<b>Value</b>: ${formattedValue}</br><b>${unitType} IDs Enabled</b>: ${unitValues.join(", ")}`;
  }

  return {
    value: currentValue,

    rolloutDetails,

    dimensions:
      fetchDetails["Param Type"] === "PARAM_TYPE_SINGLE_VALUED"
        ? "-- NA --"
        : !item || Object.keys(safeItem).length === 0
          ? "{ }"
          : dimensionStrings[i] || "{ }",

    created_at: safeItem.created_time.seconds,

    updated_at: safeItem.updated_time.seconds,

    marketplaceAttributes:
      !marketplaceStrings[i]
        ? "-- ND --"
        : marketplaceStrings[i],

    status: rolloutData?.is_in_rollout_phase
      ? "Rollout in Progress"
      : "Live"
  };
});
